  '<': '&lt;',
  '>': '&gt;',
  '"': '&quot;',
  "'": '&#039;'
};

export function sanitizeInput(input: string): string {
  return input.replace(/[<>"']/g, (char) => HTML_ENTITY_MAP[char] || char);
}

